import pandas as pd
import ast
import os

########################################################################################################################
######################## This file cleans up the resulting csv files generated by poker predict ########################
########################################################################################################################

def process_rfecv_csv(file_path):
    with open(file_path, "r", encoding="utf-8") as f:
        header_line = f.readline().strip()
        row_line = f.readline().strip()

    if not row_line:
        print(f"Skipped empty file: {file_path}")
        return

    headers = header_line.split(",")

    if len(headers) < 3:
        print(f"Skipped malformed header: {file_path}")
        return

    # Everything except the last two headers is a normal scalar column
    normal_headers = headers[:-2]

    # Split only the scalar columns off the front
    parts = row_line.split(",", len(normal_headers))

    if len(parts) != len(normal_headers) + 1:
        print(f"Could not split normal columns correctly: {file_path}")
        return

    normal_values = parts[:-1]
    tail = parts[-1]

    # Tail should be: [selected_features],[feature_names]
    split_token = "],["
    if split_token not in tail:
        print(f"Could not find feature split token in: {file_path}")
        return

    left, right = tail.split(split_token, 1)

    selected_features = ast.literal_eval(left + "]")
    feature_names = ast.literal_eval("[" + right)

    if len(selected_features) != len(feature_names):
        print(f"Length mismatch in {file_path}")
        print(f"selected_features length: {len(selected_features)}")
        print(f"feature_names length: {len(feature_names)}")
        return

    # Write extracted feature CSV
    features_df = pd.DataFrame([selected_features], columns=feature_names)
    feature_file = os.path.splitext(file_path)[0] + "_features.csv"
    features_df.to_csv(feature_file, index=False)

    # Rewrite original CSV without selected_features and feature_names
    cleaned_df = pd.DataFrame([normal_values], columns=normal_headers)
    cleaned_df.to_csv(file_path, index=False)

    print(f"RFECV processed: {file_path}")
    print(f"Feature file: {feature_file}")


def process_kpca_csv(file_path):
    df = pd.read_csv(file_path)

    if df.shape[1] < 2:
        print(f"Skipped file with too few columns: {file_path}")
        return

    removed_cols = list(df.columns[-2:])
    df = df.iloc[:, :-2]
    df.to_csv(file_path, index=False)

    print(f"KPCA cleaned: {file_path}")
    print(f"Removed columns: {removed_cols[0]}, {removed_cols[1]}")


def process_all_files(directory="CSVs"):
    for file in os.listdir(directory):
        if not file.endswith(".csv"):
            continue

        full_path = os.path.join(directory, file)

        if "RFECV" in file:
            process_rfecv_csv(full_path)
        elif "KPCA" in file:
            process_kpca_csv(full_path)


if __name__ == "__main__":
    process_all_files()